PASS = 625
BOARD_SIZE = 25
STATE_SIZE = 26


def initial_state() -> dict:
    board = [0] * BOARD_SIZE
    board[0:5] = [3, 2, 1, 2, 3]
    board[20:25] = [6, 5, 4, 5, 6]
    board.append(0)
    return {"board": board, "current_player": 1}


def _piece_owner(piece: int) -> int:
    if piece in (1, 2, 3):
        return 1
    if piece in (4, 5, 6):
        return 2
    return 0


def _piece_type(piece: int) -> int:
    if piece in (1, 4):
        return 0
    if piece in (2, 5):
        return 1
    if piece in (3, 6):
        return 2
    return -1


def _offsets_for(piece: int, player: int):
    t = _piece_type(piece)
    if t == 0:
        offsets = [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)]
    elif t == 1:
        offsets = [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)]
    elif t == 2:
        offsets = [(0, 3), (1, 2), (2, 1), (3, 0)]
    else:
        return []
    if player == 2:
        offsets = [(-dr, dc) for dr, dc in offsets]
    return offsets


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    actions = []
    for from_idx in range(BOARD_SIZE):
        piece = board[from_idx]
        if _piece_owner(piece) != player:
            continue
        r, c = divmod(from_idx, 5)
        for dr, dc in _offsets_for(piece, player):
            nr, nc = r + dr, c + dc
            if 0 <= nr < 5 and 0 <= nc < 5:
                to_idx = nr * 5 + nc
                dest = board[to_idx]
                if _piece_owner(dest) != player:
                    actions.append(from_idx * 25 + to_idx)
    return actions if actions else [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]

    if action == PASS:
        new_board[25] = board[25] + 1
        return {"board": new_board, "current_player": 3 - player}

    from_idx = action // 25
    to_idx = action % 25
    piece = new_board[from_idx]
    new_board[from_idx] = 0
    new_board[to_idx] = piece
    new_board[25] = board[25] + 1
    return {"board": new_board, "current_player": 3 - player}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    ply = board[25]
    p1_general_alive = 1 in board
    p2_general_alive = 4 in board
    return (not p1_general_alive) or (not p2_general_alive) or (ply >= 100)


def returns(state: dict) -> dict:
    board = state["board"]
    ply = board[25]
    p1_general_alive = 1 in board
    p2_general_alive = 4 in board

    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    if p1_general_alive and not p2_general_alive:
        return {1: 1.0, 2: -1.0}
    if p2_general_alive and not p1_general_alive:
        return {1: -1.0, 2: 1.0}

    return {1: 0.0, 2: 0.0}

