PASS = 625
BOARD_CELLS = 25
STATE_SIZE = 26
DRAW_PLY_LIMIT = 100

# Piece codes:
# 1 general, 2 infantry, 3 cavalry for player 1
# 4 general, 5 infantry, 6 cavalry for player 2

_OFFSETS = {
    1: [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],
    2: [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],
    3: [(0, 3), (1, 2), (2, 1), (3, 0)],
}


def initial_state() -> dict:
    return {
        "board": [3, 2, 1, 2, 3] + [0] * 15 + [6, 5, 4, 5, 6] + [0],
        "current_player": 1,
    }


def _piece_owner(piece: int) -> int:
    if 1 <= piece <= 3:
        return 1
    if 4 <= piece <= 6:
        return 2
    return 0


def _piece_type(piece: int) -> int:
    if piece in (1, 4):
        return 1
    if piece in (2, 5):
        return 2
    if piece in (3, 6):
        return 3
    return 0


def _in_bounds(r: int, c: int) -> bool:
    return 0 <= r < 5 and 0 <= c < 5


def _index_to_rc(i: int):
    return divmod(i, 5)


def _rc_to_index(r: int, c: int) -> int:
    return r * 5 + c


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    actions = []
    for from_idx in range(BOARD_CELLS):
        piece = board[from_idx]
        if _piece_owner(piece) != player:
            continue
        ptype = _piece_type(piece)
        fr, fc = _index_to_rc(from_idx)
        for dr, dc in _OFFSETS[ptype]:
            if player == 2:
                dr = -dr
            tr, tc = fr + dr, fc + dc
            if not _in_bounds(tr, tc):
                continue
            to_idx = _rc_to_index(tr, tc)
            target = board[to_idx]
            if _piece_owner(target) == player:
                continue
            actions.append(from_idx * 25 + to_idx)
    if actions:
        return actions
    return [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]
    new_ply = board[25] + 1

    if action == PASS:
        new_board[25] = new_ply
        return {"board": new_board, "current_player": 3 - player}

    from_idx = action // 25
    to_idx = action % 25
    piece = new_board[from_idx]
    new_board[from_idx] = 0
    new_board[to_idx] = piece
    new_board[25] = new_ply
    return {"board": new_board, "current_player": 3 - player}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    if board[25] >= DRAW_PLY_LIMIT:
        return True
    has_p1_general = 1 in board[:25]
    has_p2_general = 4 in board[:25]
    return not (has_p1_general and has_p2_general)


def returns(state: dict) -> dict:
    board = state["board"]
    has_p1_general = 1 in board[:25]
    has_p2_general = 4 in board[:25]

    # Draw by ply limit
    if board[25] >= DRAW_PLY_LIMIT:
        return {1: 0.0, 2: 0.0}

    # Non-terminal states always return zeroes
    if has_p1_general and has_p2_general:
        return {1: 0.0, 2: 0.0}

    # Terminal by capture of one general
    if has_p1_general and not has_p2_general:
        return {1: 1.0, 2: -1.0}
    if has_p2_general and not has_p1_general:
        return {1: -1.0, 2: 1.0}

    # If both generals are missing, treat as draw
    return {1: 0.0, 2: 0.0}

