    if piece in (P1_GENERAL, P2_GENERAL):
        offsets = _GENERAL_OFFSETS
    elif piece in (P1_INFANTRY, P2_INFANTRY):
        offsets = _INFANTRY_OFFSETS
    elif piece in (P1_CAVALRY, P2_CAVALRY):
        offsets = _CAVALRY_OFFSETS
    else:
        offsets = []

    if player == 1:
        return offsets
    return [(-dr, dc) for dr, dc in offsets]


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    actions = []

    for from_idx in range(BOARD_SIZE):
        piece = board[from_idx]
        if _owner(piece) != player:
            continue
        r, c = divmod(from_idx, 5)
        for dr, dc in _moves_for_piece(piece, player):
            nr, nc = r + dr, c + dc
            if not (0 <= nr < 5 and 0 <= nc < 5):
                continue
            to_idx = nr * 5 + nc
            target = board[to_idx]
            if _owner(target) == player:
                continue
            actions.append(from_idx * 25 + to_idx)

    if actions:
        return actions
    return [PASS]


