    board = state["board"]
    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    p1_general_alive = P1_GENERAL in board[:25]
    p2_general_alive = P2_GENERAL in board[:25]

    if p1_general_alive and not p2_general_alive:
