    if 4 <= piece <= 6:
        return 2
    return 0


def _piece_kind(piece: int) -> int:
    if piece in (1, 4):
        return 1
    if piece in (2, 5):
        return 2
    if piece in (3, 6):
        return 3
    return 0


def _in_bounds(r: int, c: int) -> bool:
    return 0 <= r < 5 and 0 <= c < 5


def legal_actions(state: dict) -> list[int]:
