        if _piece_owner(piece) != player:
            continue

        kind = _piece_kind(piece)
        fr, fc = divmod(from_idx, 5)

        for dr, dc in _OFFSETS[kind]:
            if player == 2:
                dr = -dr

            tr, tc = fr + dr, fc + dc
            if not _in_bounds(tr, tc):
                continue

            to_idx = tr * 5 + tc
            dest = board[to_idx]
            if _piece_owner(dest) == player:
