from typing import Dict, List


BOARD_SIZE = 25
PASS = 625

# Piece codes
# Player 1: 1 general, 2 infantry, 3 cavalry
# Player 2: 4 general, 5 infantry, 6 cavalry

_OFFSETS = {
    1: [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],  # general
    2: [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],            # infantry
    3: [(0, 3), (1, 2), (2, 1), (3, 0)],                      # cavalry
}


def initial_state() -> dict:
    board = [0] * 26
    board[0:5] = [3, 2, 1, 2, 3]
    board[20:25] = [6, 5, 4, 5, 6]
    board[25] = 0
    return {"board": board, "current_player": 1}


def _piece_owner(piece: int) -> int:
    if piece == 0:
        return 0
    return 1 if piece <= 3 else 2


def _piece_kind(piece: int) -> int:
    if piece in (1, 4):
        return 1
    if piece in (2, 5):
        return 2
    if piece in (3, 6):
        return 3
    return 0


def _moves_from(state: dict, from_idx: int) -> List[int]:
    board = state["board"]
    piece = board[from_idx]
    owner = _piece_owner(piece)
    if owner != state["current_player"] or piece == 0:
        return []

    row, col = divmod(from_idx, 5)
    kind = _piece_kind(piece)
    offsets = _OFFSETS[kind]
    if owner == 2:
        offsets = [(-dr, dc) for dr, dc in offsets]

    actions = []
    for dr, dc in offsets:
        nr, nc = row + dr, col + dc
        if 0 <= nr < 5 and 0 <= nc < 5:
            to_idx = nr * 5 + nc
            target = board[to_idx]
            if _piece_owner(target) != owner:
                actions.append(from_idx * 25 + to_idx)
    return actions


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    actions: List[int] = []
    for idx in range(25):
        if _piece_owner(board[idx]) == state["current_player"]:
            actions.extend(_moves_from(state, idx))
    if not actions:
