    board[0:5] = [3, 2, 1, 2, 3]
    board[20:25] = [6, 5, 4, 5, 6]
    board[25] = 0
    return {"board": board, "current_player": 1}


def _friendly_set(player: int) -> set[int]:
    return P1_PIECES if player == 1 else P2_PIECES


def _piece_type(piece: int) -> int:
    if piece in (P1_GENERAL, P2_GENERAL):
        return 1
    if piece in (P1_INFANTRY, P2_INFANTRY):
        return 2
    if piece in (P1_CAVALRY, P2_CAVALRY):
        return 3
    return 0


def _piece_offsets(piece: int, player: int) -> list[tuple[int, int]]:
    base = PIECE_OFFSETS[_piece_type(piece)]
    if player == 1:
        return base
    return [(-dr, dc) for dr, dc in base]


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    friendly = _friendly_set(player)
    actions: list[int] = []

    for from_idx in range(BOARD_SIZE):
        piece = board[from_idx]
        if piece not in friendly:
            continue
        r, c = divmod(from_idx, 5)
        for dr, dc in _piece_offsets(piece, player):
            nr, nc = r + dr, c + dc
            if 0 <= nr < 5 and 0 <= nc < 5:
                to_idx = nr * 5 + nc
                target = board[to_idx]
                if target == 0 or target not in friendly:
                    actions.append(from_idx * 25 + to_idx)

    return actions if actions else [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board.copy()

    if action == PASS:
        new_board[25] = board[25] + 1
        return {"board": new_board, "current_player": 2 if player == 1 else 1}

    from_idx, to_idx = divmod(action, 25)
    moving_piece = new_board[from_idx]
    new_board[from_idx] = 0
    new_board[to_idx] = moving_piece
    new_board[25] = board[25] + 1
    return {"board": new_board, "current_player": 2 if player == 1 else 1}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    ply = board[25]
    p1_alive = P1_GENERAL in board[:25]
