    board = state["board"]
    ply = board[25]
    p1_alive = P1_GENERAL in board[:25]
    p2_alive = P2_GENERAL in board[:25]

    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    # Draw on ply limit when both generals are still alive.
    if ply >= 100 and p1_alive and p2_alive:
        return {1: 0.0, 2: 0.0}

    # If both generals are gone, treat as draw.
    if not p1_alive and not p2_alive:
