    P2_GENERAL: "general",
    P2_INFANTRY: "infantry",
    P2_CAVALRY: "cavalry",
}

OFFSETS = {
    "general": [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],
    "infantry": [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],
    "cavalry": [(0, 3), (1, 2), (2, 1), (3, 0)],
}


