    return {"board": board, "current_player": 1}


def _rc(index: int) -> tuple[int, int]:
    return divmod(index, BOARD_SIZE)


def _idx(row: int, col: int) -> int:
    return row * BOARD_SIZE + col


def _moves_for_piece(piece: int, player: int) -> list[tuple[int, int]]:
    kind = PIECE_TYPE[piece]
    base = OFFSETS[kind]
    if player == 1:
        return base
    return [(-dr, dc) for dr, dc in base]


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    actions: list[int] = []

    for frm in range(NUM_CELLS):
        piece = board[frm]
        if piece == 0 or PIECE_OWNER[piece] != player:
            continue
        fr, fc = _rc(frm)
        for dr, dc in _moves_for_piece(piece, player):
            tr, tc = fr + dr, fc + dc
            if 0 <= tr < BOARD_SIZE and 0 <= tc < BOARD_SIZE:
                to = _idx(tr, tc)
                target = board[to]
                if target == 0 or PIECE_OWNER[target] != player:
                    actions.append(frm * 25 + to)

    return actions if actions else [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]

    if action == PASS:
        new_board[PLY_INDEX] = board[PLY_INDEX] + 1
        return {"board": new_board, "current_player": 3 - player}

    frm, to = divmod(action, 25)
    piece = board[frm]
    new_board[frm] = 0
    new_board[to] = piece
    new_board[PLY_INDEX] = board[PLY_INDEX] + 1
    return {"board": new_board, "current_player": 3 - player}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    plies = board[PLY_INDEX]
    p1_general_alive = P1_GENERAL in board[:25]
    p2_general_alive = P2_GENERAL in board[:25]
    return (not p1_general_alive) or (not p2_general_alive) or (plies >= 100)


def returns(state: dict) -> dict:
    board = state["board"]
    p1_general_alive = P1_GENERAL in board[:25]
    p2_general_alive = P2_GENERAL in board[:25]
    plies = board[PLY_INDEX]

    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    if p1_general_alive and not p2_general_alive:
        return {1: 1.0, 2: -1.0}
    if p2_general_alive and not p1_general_alive:
        return {1: -1.0, 2: 1.0}

    # Draw for ply limit or any other terminal draw condition.
    if plies >= 100 or (not p1_general_alive and not p2_general_alive):
        return {1: 0.0, 2: 0.0}

    return {1: 0.0, 2: 0.0}

