    next_player = 2 if player == 1 else 1

    if action == PASS:
        return {"board": new_board, "current_player": next_player}

    from_idx = action // 25
    to_idx = action % 25

    piece = new_board[from_idx]
    new_board[from_idx] = 0
    new_board[to_idx] = piece

