    p2_general_alive = _has_general(board, 2)

    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    # Draw by ply limit when both generals are still alive.
    if board[PLY_INDEX] >= 100 and p1_general_alive and p2_general_alive:
        return {1: 0.0, 2: 0.0}

    # Winner is the side whose general is alive.
    if p1_general_alive and not p2_general_alive:
