from __future__ import annotations

from typing import List

BOARD_SIZE = 5
NUM_CELLS = 25
PLY_INDEX = 25
PASS = 625

P1 = {1, 2, 3}
P2 = {4, 5, 6}

OFFSETS = {
    1: [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],
    2: [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],
    3: [(0, 3), (1, 2), (2, 1), (3, 0)],
}


def initial_state() -> dict:
    board = [0] * 26
    board[0:5] = [3, 2, 1, 2, 3]
    board[20:25] = [6, 5, 4, 5, 6]
    board[25] = 0
    return {"board": board, "current_player": 1}


def _owner(piece: int) -> int | None:
    if piece in P1:
        return 1
    if piece in P2:
        return 2
    return None


def _piece_kind(piece: int) -> int | None:
    if piece in (1, 4):
        return 1
    if piece in (2, 5):
        return 2
    if piece in (3, 6):
        return 3
    return None


def _rc(index: int) -> tuple[int, int]:
    return divmod(index, BOARD_SIZE)


def _idx(r: int, c: int) -> int:
    return r * BOARD_SIZE + c


def _general_alive(board: List[int], player: int) -> bool:
    return (1 if player == 1 else 4) in board[:NUM_CELLS]


def is_terminal(state: dict) -> bool:
    board = state["board"]
    return board[PLY_INDEX] >= 100 or not _general_alive(board, 1) or not _general_alive(board, 2)


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]

    if is_terminal(state):
        return [PASS]

    friendly = P1 if player == 1 else P2
    actions: List[int] = []

    for i in range(NUM_CELLS):
        piece = board[i]
        if piece not in friendly:
            continue
        kind = _piece_kind(piece)
        if kind is None:
            continue

        r, c = _rc(i)
        for dr, dc in OFFSETS[kind]:
            if player == 2:
                dr = -dr
            nr, nc = r + dr, c + dc
            if 0 <= nr < BOARD_SIZE and 0 <= nc < BOARD_SIZE:
                j = _idx(nr, nc)
                dst = board[j]
                if dst not in friendly:
                    actions.append(i * 25 + j)

    return actions if actions else [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board.copy()

    if action != PASS:
        from_idx = action // 25
        to_idx = action % 25
        piece = new_board[from_idx]
        new_board[from_idx] = 0
        new_board[to_idx] = piece

    new_board[PLY_INDEX] = board[PLY_INDEX] + 1
    next_player = 2 if player == 1 else 1
    return {"board": new_board, "current_player": next_player}


def returns(state: dict) -> dict:
    board = state["board"]
    g1 = _general_alive(board, 1)
    g2 = _general_alive(board, 2)
    plies = board[PLY_INDEX]

    if not g1 and not g2:
        return {1: 0.0, 2: 0.0}
    if not g1:
        return {1: -1.0, 2: 1.0}
    if not g2:
        return {1: 1.0, 2: -1.0}
    if plies >= 100:
        return {1: 0.0, 2: 0.0}

    return {1: 0.0, 2: 0.0}
